#include <iostream>
#include <string>
#include <stdexcept>

class BankAccount {
private:
    std::string ownerName;
    double balance;

public:
    // 构造函数
    BankAccount(std::string name, double initialBalance) {
        ownerName = name;
        if (initialBalance < 0) {
            balance = 0;
        } else {
            balance = initialBalance;
        }
    }

    void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            std::cout << "存款 " << amount << " 成功。" << std::endl;
        } else {
            std::cout << "存款金额必须为正数。" << std::endl;
        }
    }

    void withdraw(double amount) {
        if (amount > balance) {
            throw std::runtime_error("余额不足，无法取款。");
        } else if (amount <= 0) {
            throw std::invalid_argument("取款金额必须为正数。");
        } else {
            balance -= amount;
            std::cout << "取款 " << amount << " 成功。" << std::endl;
        }
    }

    void displayBalance() const {
        std::cout << "账户: " << ownerName << ", 当前余额: " << balance << std::endl;
    }
};

int main() {
    BankAccount myAccount("张三", 500.0);
    myAccount.displayBalance();

    myAccount.deposit(150.0);
    myAccount.displayBalance();

    try {
        myAccount.withdraw(200.0);
        myAccount.displayBalance();

        // 尝试取款超过余额
        myAccount.withdraw(1000.0);

    } catch (const std::runtime_error& e) {
        std::cerr << "错误: " << e.what() << std::endl;
        myAccount.displayBalance();
    } catch (const std::invalid_argument& e) {
        std::cerr << "错误: " << e.what() << std::endl;
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>

#define IN 1  // 在单词内
#define OUT 0 // 在单词外

int main() {
    FILE *file;
    char *filename = "example.txt";
    char c;
    int lines = 0, words = 0, chars = 0;
    int state = OUT;

    // 创建一个示例文本文件
    file = fopen(filename, "w");
    if (file == NULL) {
        printf("无法创建文件。\n");
        return 1;
    }
    fprintf(file, "Hello World,\nthis is a test file.\nLet's count the words.\n");
    fclose(file);

    // 打开文件进行读取
    file = fopen(filename, "r");
    if (file == NULL) {
        printf("无法打开文件 %s\n", filename);
        return 1;
    }

    printf("正在处理文件: %s\n\n", filename);

    while ((c = fgetc(file)) != EOF) {
        chars++;
        if (c == '\n') {
            lines++;
        }
        if (isspace(c)) {
            state = OUT;
        } else if (state == OUT) {
            state = IN;
            words++;
        }
    }

    fclose(file);

    // 如果文件不以换行符结尾，但包含内容，则行数加一
    if (chars > 0 && lines == 0) {
        lines = 1;
    }


    printf("--- 文件统计 ---\n");
    printf("字符数: %d\n", chars);
    printf("单词数: %d\n", words);
    printf("行数  : %d\n", lines);

    return 0;
}

package main

import (
    "fmt"
    "io/ioutil"
    "net/http"
    "sync"
    "time"
)

func fetchURL(url string, wg *sync.WaitGroup, ch chan<- string) {
    defer wg.Done()

    start := time.Now()
    resp, err := http.Get(url)
    if err != nil {
        ch <- fmt.Sprintf("获取 %s 失败: %v", url, err)
        return
    }
    defer resp.Body.Close()

    bodyBytes, err := ioutil.ReadAll(resp.Body)
    if err != nil {
        ch <- fmt.Sprintf("读取 %s 响应失败: %v", url, err)
        return
    }

    elapsed := time.Since(start).Seconds()
    ch <- fmt.Sprintf("从 %s 获取了 %d 字节, 用时 %.2f 秒", url, len(bodyBytes), elapsed)
}

func main() {
    urls := []string{
        "https://jsonplaceholder.typicode.com/todos/1",
        "https://jsonplaceholder.typicode.com/posts/1",
        "https://jsonplaceholder.typicode.com/users/1",
    }

    var wg sync.WaitGroup
    ch := make(chan string, len(urls))

    fmt.Println("开始并发获取 URL...")

    for _, url := range urls {
        wg.Add(1)
        go fetchURL(url, &wg, ch)
    }

    // 等待所有 goroutine 完成
    wg.Wait()
    close(ch)

    // 从 channel 中读取所有结果
    for result := range ch {
        fmt.Println(result)
    }

    fmt.Println("所有任务完成。")
}
